        require(!candidateExists[candidateId], "Candidate exists");
        candidateExists[candidateId] = true;
        candidateList.push(candidateId);
        emit CandidateRegistered(candidateId);
    }

    function vote(uint256 candidateId) external whenVotingActive {
        require(candidateExists[candidateId], "Invalid candidate");
        require(!hasVoted[msg.sender], "Already voted");
        require(msg.sender != admin, "Admin cannot vote");
        hasVoted[msg.sender] = true;
        votes[candidateId] += 1;
        emit VoteCast(msg.sender, candidateId);
    }

    function endVoting() external onlyAdmin whenVotingActive {
        votingActive = false;
        emit VotingEnded();
    }

    function getWinner() external view returns (uint256 winnerId, uint256 winnerVotes) {
