pragma solidity ^0.8.0;

contract SimpleVoting {
    address public owner;
    bool public votingActive = true;

    struct Candidate {
        uint256 id;
        string name;
        uint256 voteCount;
    }

    mapping(uint256 => Candidate) public candidates;
    mapping(uint256 => bool) public candidateExists;
    uint256[] public candidateIds;
    mapping(address => bool) public hasVoted;

    event CandidateRegistered(uint256 indexed id, string name);
    event VoteCast(address indexed voter, uint256 indexed candidateId);
    event VotingEnded(uint256 winnerId, string winnerName);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function registerCandidate(uint256 id, string calldata name) external onlyOwner {
        require(votingActive, "Voting ended");
        require(!candidateExists[id], "Candidate exists");
        candidates[id] = Candidate(id, name, 0);
        candidateExists[id] = true;
        candidateIds.push(id);
        emit CandidateRegistered(id, name);
    }

    function vote(uint256 candidateId) external {
        require(votingActive, "Voting ended");
        require(msg.sender != owner, "Owner cannot vote");
        require(!hasVoted[msg.sender], "Already voted");
        require(candidateExists[candidateId], "Candidate does not exist");
        candidates[candidateId].voteCount += 1;
        hasVoted[msg.sender] = true;
        emit VoteCast(msg.sender, candidateId);
    }

    function endVoting() external onlyOwner {
        require(votingActive, "Voting already ended");
        votingActive = false;
        (uint256 winnerId, string memory winnerName) = _getWinnerInternal();
        emit VotingEnded(winnerId, winnerName);
    }

    function _getWinnerInternal() internal view returns (uint256, string memory) {
        require(candidateIds.length > 0, "No candidates");
        uint256 maxVotes = 0;
        uint256 winnerId = 0;
        string memory winnerName = "";
        for (uint256 i = 0; i < candidateIds.length; i++) {
            uint256 id = candidateIds[i];
            uint256 votes = candidates[id].voteCount;
            if (votes > maxVotes) {
                maxVotes = votes;
                winnerId = id;
                winnerName = candidates[id].name;
            }
        }
        return (winnerId, winnerName);
    }

    function getWinner() external view returns (uint256, string memory) {
        require(!votingActive, "Voting not ended");
        return _getWinnerInternal();
    }

    function getCandidate(uint256 id) external view returns (string memory name, uint256 voteCount) {
        require(candidateExists[id], "Candidate does not exist");
        Candidate storage c = candidates[id];
        return (c.name, c.voteCount);
    }

    function hasVotedAddress(address voter) external view returns (bool) {
        return hasVoted[voter];
    }

    function isVotingActive() external view returns (bool) {
        return votingActive;
    }

    function getCandidateIds() external view returns (uint256[] memory) {
        return candidateIds;
    }

    function getCandidateCount() external view returns (uint256) {
        return candidateIds.length;
    }
}

pragma solidity ^0.8.20;

contract SimpleERC20 {
    string public constant name = "SimpleToken";
    string public constant symbol = "SIM";
    uint8 public constant decimals = 18;
    uint256 public immutable totalSupply;

    mapping(address => uint256) private _balances;
    mapping(address => mapping(address => uint256)) private _allowances;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    constructor(uint256 initialSupply) {
        totalSupply = initialSupply * 10 ** uint256(decimals);
        _balances[msg.sender] = totalSupply;
        emit Transfer(address(0), msg.sender, totalSupply);
    }

    function balanceOf(address account) external view returns (uint256) {
        return _balances[account];
    }

    function allowance(address owner, address spender) external view returns (uint256) {
        return _allowances[owner][spender];
    }

    function transfer(address to, uint256 amount) external returns (bool) {
        _transfer(msg.sender, to, amount);
        return true;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        _approve(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        uint256 currentAllowance = _allowances[from][msg.sender];
        require(currentAllowance >= amount, "ERC20: transfer amount exceeds allowance");
        _approve(from, msg.sender, currentAllowance - amount);
        _transfer(from, to, amount);
        return true;
    }

    function _transfer(address from, address to, uint256 amount) internal {
        require(to != address(0), "ERC20: transfer to the zero address");
        uint256 senderBalance = _balances[from];
        require(senderBalance >= amount, "ERC20: transfer amount exceeds balance");
        _balances[from] = senderBalance - amount;
        _balances[to] += amount;
        emit Transfer(from, to, amount);
