contract Escrow {
    enum State { Created, Delivered, Released, Refunded, Disputed }
    State public state;
    address public immutable buyer;
    address public immutable seller;
    address public immutable arbiter;
    uint256 public immutable amount;

    bool private _locked;

    event Created(address indexed buyer, address indexed seller, address indexed arbiter, uint256 amount);
    event Delivered();
    event Released();
    event Refunded();
    event Disputed();
    event Resolved(bool toSeller);

    modifier onlyBuyer() {
        require(msg.sender == buyer, "Not buyer");
        _;
    }

    modifier onlySeller() {
        require(msg.sender == seller, "Not seller");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == arbiter, "Not arbiter");
        _;
    }

    modifier inState(State expected) {
        require(state == expected, "Invalid state");
        _;
    }

    modifier nonReentrant() {
        require(!_locked, "Reentrancy");
        _locked = true;
        _;
        _locked = false;
    }

    constructor(address _buyer, address _seller, address _arbiter) payable {
        require(_buyer != address(0) && _seller != address(0) && _arbiter != address(0), "Zero address");
        require(_buyer != _seller && _buyer != _arbiter && _seller != _arbiter, "Addresses must be unique");
        require(msg.sender == _buyer, "Buyer must send funds");
        require(msg.value > 0, "No funds");
        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        amount = msg.value;
        state = State.Created;
        emit Created(buyer, seller, arbiter, amount);
    }

    function markDelivered() external onlySeller inState(State.Created) {
        state = State.Delivered;
        emit Delivered();
    }

    function release() external onlyBuyer inState(State.Delivered) nonReentrant {
        state = State.Released;
        (bool success, ) = seller.call{value: amount}("");
        require(success, "Transfer failed");
        emit Released();
    }

    function dispute() external inState(State.Delivered) {
        require(msg.sender == buyer || msg.sender == seller, "Not buyer or seller");
        state = State.Disputed;
        emit Disputed();
    }

    function resolve(bool toSeller) external onlyArbiter inState(State.Disputed) nonReentrant {
        state = toSeller ? State.Released : State.Refunded;
        address recipient = toSeller ? seller : buyer;
        (bool success, ) = recipient.call{value: amount}("");
        require(success, "Transfer failed");
        emit Resolved(toSeller);
        if (toSeller) {
            emit Released();
        } else {
            emit Refunded();
        }
    }

    receive() external payable {
        revert("No deposits allowed");
    }
}

