        buyer = msg.sender;
        seller = _seller;
        arbiter = _arbiter;
        deposit = msg.value;
        state = State.Created;

        emit EscrowCreated(buyer, seller, arbiter, deposit);
    }

    function markDelivered() external onlySeller inState(State.Created) {
        state = State.Delivered;
        emit Delivered(seller);
    }

    function releasePayment() external onlyBuyer inState(State.Delivered) nonReentrant {
        state = State.Released;
        uint256 amount = address(this).balance;
        (bool success, ) = seller.call{value: amount}("");
        require(success, "Transfer to seller failed");
        emit Released(seller, amount);
    }

    function dispute() external inState(State.Delivered) {
        require(msg.sender == buyer || msg.sender == seller, "Only buyer or seller");
        state = State.Disputed;
        emit Disputed(msg.sender);
    }

    function arbiterResolve(bool toSeller) external onlyArbiter inState(State.Disputed) nonReentrant {
        uint256 amount = address(this).balance;
        if (toSeller) {
            state = State.Released;
            (bool success, ) = seller.call{value: amount}("");
            require(success, "Transfer to seller failed");
            emit Resolved(arbiter, true, amount);
        } else {
            state = State.Refunded;
            (bool success, ) = buyer.call{value: amount}("");
            require(success, "Refund to buyer failed");
            emit Resolved(arbiter, false, amount);
        }
    }
}

