    bytes32 public constant USER_ROLE = keccak256("USER_ROLE");

    mapping(bytes32 => mapping(address => bool)) private _roles;
    uint256 private _adminCount;

    event RoleGranted(bytes32 indexed role, address indexed account, address indexed sender);
    event RoleRevoked(bytes32 indexed role, address indexed account, address indexed sender);

    modifier onlyRole(bytes32 role) {
        require(_roles[role][msg.sender], "AccessControl: account missing role");
        _;
    }

    constructor() {
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    function hasRole(bytes32 role, address account) public view returns (bool) {
        return _roles[role][account];
    }

    function grantRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _grantRole(role, account);
    }

    function revokeRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _revokeRole(role, account);
    }

    function renounceRole(bytes32 role) external {
        _revokeRole(role, msg.sender);
    }

    function adminFunction() external onlyRole(ADMIN_ROLE) returns (string memory) {
        return "Admin function executed";
    }

    function managerFunction() external onlyRole(MANAGER_ROLE) returns (string memory) {
        return "Manager function executed";
    }

    function userFunction() external onlyRole(USER_ROLE) returns (string memory) {
        return "User function executed";
    }

    function _grantRole(bytes32 role, address account) internal {
        require(account != address(0), "AccessControl: zero address");
        if (!_roles[role][account]) {
            _roles[role][account] = true;
            if (role == ADMIN_ROLE) {
                _adminCount++;
            }
            emit RoleGranted(role, account, msg.sender);
        }
    }

    function _revokeRole(bytes32 role, address account) internal {
        require(account != address(0), "AccessControl: zero address");
        if (_roles[role][account]) {
            if (role == ADMIN_ROLE) {
                require(_adminCount > 1, "AccessControl: cannot revoke last admin");
                _adminCount--;
            }
            _roles[role][account] = false;
            emit RoleRevoked(role, account, msg.sender);
        }
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract RBAC {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant MANAGER_ROLE = keccak256("MANAGER_ROLE");
    bytes32 public constant USER_ROLE = keccak256("USER_ROLE");

    mapping(bytes32 => mapping(address => bool)) private _roles;
    uint256 private _adminCount;

    event RoleGranted(bytes32 indexed role, address indexed account, address indexed sender);
    event RoleRevoked(bytes32 indexed role, address indexed account, address indexed sender);

    error AccessControlMissingRole(bytes32 role, address account);
    error ZeroAddress();
    error NoAdminsLeft();
    error RoleAlreadyGranted();
    error RoleNotGranted();

    constructor() {
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    modifier onlyRole(bytes32 role) {
        if (!hasRole(role, msg.sender)) revert AccessControlMissingRole(role, msg.sender);
        _;
    }

    function hasRole(bytes32 role, address account) public view returns (bool) {
        return _roles[role][account];
    }

    function grantRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _grantRole(role, account);
    }

    function revokeRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _revokeRole(role, account);
    }

    function renounceRole(bytes32 role) external {
        _revokeRole(role, msg.sender);
    }

    function _grantRole(bytes32 role, address account) internal {
        if (account == address(0)) revert ZeroAddress();
        if (_roles[role][account]) revert RoleAlreadyGranted();
        _roles[role][account] = true;
        if (role == ADMIN_ROLE) _adminCount++;
        emit RoleGranted(role, account, msg.sender);
    }

    function _revokeRole(bytes32 role, address account) internal {
        if (account == address(0)) revert ZeroAddress();
        if (!_roles[role][account]) revert RoleNotGranted();
        _roles[role][account] = false;
        if (role == ADMIN_ROLE) {
            if (_adminCount <= 1) revert NoAdminsLeft();
            _adminCount--;
        }
        emit RoleRevoked(role, account, msg.sender);
    }

    // Sample functions demonstrating role requirements
    function adminOnly() external onlyRole(ADMIN_ROLE) returns (string memory) {
        return "admin function";
    }

    function managerOnly() external onlyRole(MANAGER_ROLE) returns (string memory) {
        return "manager function";
    }

    function userOnly() external onlyRole(USER_ROLE) returns (string memory) {
        return "user function";
    }
}

