pragma solidity ^0.8.0;

contract Escrow {
    enum State {
        Created,
        Delivered,
        Released,
        Refunded,
        Disputed
    }

    struct Dispute {
        address arbiter;
        uint256 amountToBuyer;
        uint256 amountToSeller;
    }

    address public buyer;
    address public seller;
    address public arbiter;
    uint256 public amount;
    State public state;
    bool public reentrancyGuard;

    event StateChanged(State indexed newState);
    event FundsReleased(address indexed recipient, uint256 amount);
    event DisputeCreated(address indexed arbiter);
    event DisputeResolved(address indexed arbiter, address indexed winner, uint256 amount);

    constructor(address _buyer, address _seller, address _arbiter, uint256 _amount) payable {
        require(_buyer != address(0), "Buyer address cannot be zero");
        require(_seller != address(0), "Seller address cannot be zero");
        require(_arbiter != address(0), "Arbiter address cannot be zero");
        require(_buyer != _seller, "Buyer and seller addresses cannot be the same");
        require(_buyer != _arbiter, "Buyer and arbiter addresses cannot be the same");
        require(_seller != _arbiter, "Seller and arbiter addresses cannot be the same");
        require(msg.value == _amount, "Incorrect amount sent");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        amount = _amount;
        state = State.Created;
    }

    function deliverItem() public {
        require(msg.sender == seller, "Only seller can deliver item");
        require(state == State.Created, "Item already delivered or contract finalized");

        state = State.Delivered;
        emit StateChanged(State.Delivered);
    }

    function releasePayment() public {
        require(msg.sender == buyer, "Only buyer can release payment");
        require(state == State.Delivered, "Item not delivered yet or contract finalized");

        state = State.Released;
        emit StateChanged(State.Released);
        emit FundsReleased(seller, amount);
        (bool success, ) = seller.call{value: amount}("");
        require(success, "Transfer failed");
    }

    function dispute() public {
        require(msg.sender == buyer, "Only buyer can initiate dispute");
        require(state == State.Delivered, "Dispute can only be initiated after delivery");
        require(arbiter != address(0), "Arbiter address is not set");

        state = State.Disputed;
        emit StateChanged(State.Disputed);
        emit DisputeCreated(arbiter);
    }

    function resolveDispute(bool toBuyer) public {
        require(msg.sender == arbiter, "Only arbiter can resolve dispute");
        require(state == State.Disputed, "Dispute not initiated");

        uint256 amountToBuyer = toBuyer ? amount : 0;
        uint256 amountToSeller = !toBuyer ? amount : 0;

        state = State.Released;
        emit StateChanged(State.Released);
        emit DisputeResolved(arbiter, toBuyer ? buyer : seller, toBuyer ? amountToBuyer : amountToSeller);

        (bool successBuyer, ) = buyer.call{value: amountToBuyer}("");
        require(successBuyer, "Transfer to buyer failed");
        (bool successSeller, ) = seller.call{value: amountToSeller}("");
        require(successSeller, "Transfer to seller failed");
    }

    function refund() public {
        require(msg.sender == arbiter, "Only arbiter can refund");
        require(state == State.Disputed, "Refund can only be done during dispute");

        state = State.Refunded;
        emit StateChanged(State.Refunded);
        emit FundsReleased(buyer, amount);
        (bool success, ) = buyer.call{value: amount}("");
        require(success, "Refund failed");
    }

    receive() external payable {
        revert("This contract does not accept direct ether transfers");
    }

    fallback() external payable {
        revert("This contract does not accept arbitrary calls");
    }
}

