contract SimpleVotingSystem {
    struct Candidate {
        uint256 id;
        string name;
        uint256 voteCount;
    }

    address public admin;
    bool public votingActive;
    mapping(address => bool) public voters;
    mapping(uint256 => Candidate) public candidates;
    uint256[] public candidateIds;

    event CandidateRegistered(uint256 id, string name);
    event VoteCast(uint256 candidateId, address voter);
    event VotingEnded(uint256 winningCandidateId);

    constructor() {
        admin = msg.sender;
        votingActive = true;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not authorized");
        _;
    }

    function registerCandidate(uint256 id, string memory name) external onlyAdmin {
        require(!candidateExists(id), "Candidate already registered");
        candidates[id] = Candidate(id, name, 0);
        candidateIds.push(id);
        emit CandidateRegistered(id, name);
    }

    function vote(uint256 candidateId) external {
        require(votingActive, "Voting has ended");
        require(!voters[msg.sender], "Already voted");
        require(candidateExists(candidateId), "Candidate does not exist");

        voters[msg.sender] = true;
        candidates[candidateId].voteCount++;
        emit VoteCast(candidateId, msg.sender);
    }

    function endVoting() external onlyAdmin {
        require(votingActive, "Voting has already ended");
        votingActive = false;

        uint256 winningCandidateId = 0;
