contract SimpleVotingSystem {
    struct Candidate {
        uint256 id;
        string name;
        uint256 voteCount;
    }

    address public admin;
    bool public votingActive;
    mapping(address => bool) public voters;
    mapping(uint256 => Candidate) public candidates;
    uint256[] public candidateIds;

    event CandidateRegistered(uint256 id, string name);
    event VoteCast(address voter, uint256 candidateId);
    event VotingEnded(uint256 winningCandidateId);

    constructor() {
        admin = msg.sender;
        votingActive = true;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not authorized");
        _;
    }

    function registerCandidate(string memory name) external onlyAdmin {
        uint256 candidateId = candidateIds.length + 1;
        candidates[candidateId] = Candidate(candidateId, name, 0);
        candidateIds.push(candidateId);
        emit CandidateRegistered(candidateId, name);
    }

    function vote(uint256 candidateId) external {
        require(votingActive, "Voting has ended");
        require(!voters[msg.sender], "Already voted");
        require(candidates[candidateId].id > 0, "Candidate does not exist");

        voters[msg.sender] = true;
        candidates[candidateId].voteCount++;
        emit VoteCast(msg.sender, candidateId);
    }

    function endVoting() external onlyAdmin {
        require(votingActive, "Voting has already ended");
        votingActive = false;

        uint256 winningCandidateId = 0;
        for (uint256 i = 0; i < candidateIds.length; i++) {
            if (candidates[candidateIds[i]].voteCount > candidates[winningCandidateId].voteCount) {
                winningCandidateId = candidateIds[i];
            }
        }

        emit VotingEnded(winningCandidateId);
    }

    function getWinningCandidate() external view returns (uint256, string memory) {
        require(!votingActive, "Voting has not ended yet");
        uint256 winningCandidateId = 0;
        for (uint256 i = 0; i < candidateIds.length; i++) {
            if (candidates[candidateIds[i]].voteCount > candidates[winningCandidateId].voteCount) {
                winningCandidateId = candidateIds[i];
            }
        }
        return (winningCandidateId, candidates[winningCandidateId].name);
    }
}

