contract RBAC {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant MANAGER_ROLE = keccak256("MANAGER_ROLE");
    bytes32 public constant USER_ROLE = keccak256("USER_ROLE");

    mapping(bytes32 => mapping(address => bool)) private roles;
    address[] private admins;

    event RoleGranted(bytes32 indexed role, address indexed account);
    event RoleRevoked(bytes32 indexed role, address indexed account);

    modifier onlyAdmin() {
        require(isAdmin(msg.sender), "Caller is not an admin");
        _;
    }

    modifier hasRole(bytes32 role) {
        require(hasUserRole(role, msg.sender), "Caller does not have the required role");
        _;
    }

    constructor() {
        grantRole(ADMIN_ROLE, msg.sender);
        admins.push(msg.sender);
    }

    function isAdmin(address account) public view returns (bool) {
        return hasUserRole(ADMIN_ROLE, account);
    }

    function isManager(address account) public view returns (bool) {
        return hasUserRole(MANAGER_ROLE, account);
    }

    function isUser(address account) public view returns (bool) {
        return hasUserRole(USER_ROLE, account);
    }

    function grantRole(bytes32 role, address account) public onlyAdmin {
        require(account != address(0), "Invalid address");
        if (!hasUserRole(role, account)) {
            roles[role][account] = true;
            emit RoleGranted(role, account);
        }
    }

    function revokeRole(bytes32 role, address account) public onlyAdmin {
        require(account != address(0), "Invalid address");
        if (hasUserRole(role, account)) {
            roles[role][account] = false;
            emit RoleRevoked(role, account);
        }
    }

    function renounceRole(bytes32 role) public {
        require(hasUserRole(role, msg.sender), "Caller does not have the role to renounce");
        roles[role][msg.sender] = false;
        emit RoleRevoked(role, msg.sender);
    }

    function hasUserRole(bytes32 role, address account) public view returns (bool) {
        return roles[role][account];
    }

    function getAdmins() external view returns (address[] memory) {
        return admins;
    }
}

