contract VotingSystem {
    // Structure to store candidate details
    struct Candidate {
        uint voteCount;
    }

    mapping(uint => Candidate) private candidates;
    mapping(address => bool) private voters;

    uint public totalCandidates = 0;
    address public admin;
    bool public votingOpen = false;

    event candidateRegistered (
        uint indexed _candidateId, 
        string _name
    );

    event voteCast(
        uint indexed _candidateId,
        address voter
    );

    event votingEnded();

    constructor() {
        admin = msg.sender;
    }

    // Modifier to restrict function access to the contract owner (admin)
    modifier onlyAdmin {
        require(msg.sender == admin, "Only admin can perform this action");
        _;
    }

    // Function to register a new candidate
    function registerCandidate() public onlyAdmin {
        uint id = totalCandidates;
        candidates[id].voteCount = 0;
        totalCandidates++;

        emit candidateRegistered(id, "Candidate");
    }

    // Function to cast a vote for a specific candidate
    function vote(uint _candidateId) public {
        require(voters[msg.sender] == false, "One vote per address allowed");
        require(_candidateId < totalCandidates, "Invalid candidate Id");
        require(votingOpen, "Voting period is over");

        voters[msg.sender] = true;
        candidates[_candidateId].voteCount += 1;

        emit voteCast(_candidateId, msg.sender);
    }

    // Function to end voting and determine the winner
    function endVoting() public onlyAdmin {
        require(votingOpen, "Voting period is already over");
        votingOpen = false;

        uint maxVotes = 0;
        uint winningCandidate = 0;

        for (uint i=0; i<totalCandidates; i++) {
            if(candidates[i].voteCount > maxVotes){
                maxVotes = candidates[i].voteCount;
                winningCandidate = i;
            }
        }

        emit votingEnded();
    }

    // Function to return the winner of the election
    function getWinner() public view returns (uint) {
        require(!votingOpen, "Voting is still open");

        uint maxVotes = 0;
        uint winningCandidate = 0;

        for (uint i=0; i<totalCandidates; i++) {
            if(candidates[i].voteCount > maxVotes){
                maxVotes = candidates[i].voteCount;
                winningCandidate = i;
            }
        }

        return winningCandidate;
    }
}

