/**
 * @title HighestBidAuction
 * @notice Implements a highest‑bid auction with automatic refunds and pull‑payment withdrawals.
 */
contract HighestBidAuction {
    /* -------------------------------------------------------------------------- */
    /*                                 State Variables                              */
    /* -------------------------------------------------------------------------- */

    address public immutable owner;
    uint256 public immutable startTime;
    uint256 public immutable endTime;
    uint256 public immutable minBid;

    address public highestBidder;
    uint256 public highestBid;

    bool public ended;

    // Mapping of address to amount that can be withdrawn (pull payments)
    mapping(address => uint256) public pendingReturns;

    /* -------------------------------------------------------------------------- */
    /*                                 Events                                      */
    /* -------------------------------------------------------------------------- */

    event NewBid(address indexed bidder, uint256 amount);
    event AuctionEnded(address indexed winner, uint256 amount);
    event Withdrawal(address indexed withdrawer, uint256 amount);

    /* -------------------------------------------------------------------------- */
    /*                                 Modifiers                                   */
    /* -------------------------------------------------------------------------- */

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    modifier onlyDuringAuction() {
        require(block.timestamp >= startTime, "Auction not started");
        require(block.timestamp <= endTime, "Auction ended");
        _;
    }

    modifier onlyAfterAuction() {
        require(block.timestamp > endTime, "Auction not finished");
        _;
    }

    /* -------------------------------------------------------------------------- */
    /*                                 Constructor                                 */
    /* -------------------------------------------------------------------------- */

    /**
     * @dev Deploys the auction contract.
     * @param _startTime Unix timestamp when the auction starts.
     * @param _endTime Unix timestamp when the auction ends.
     * @param _minBid Minimum bid amount in wei.
     */
    constructor(
        uint256 _startTime,
        uint256 _endTime,
        uint256 _minBid
    ) {
        require(_startTime < _endTime, "Start must be before end");
        require(_minBid > 0, "Minimum bid must be > 0");

        owner = msg.sender;
        startTime = _startTime;
        endTime = _endTime;
        minBid = _minBid;
    }

    /* -------------------------------------------------------------------------- */
    /*                                 Bidding Logic                              */
    /* -------------------------------------------------------------------------- */

    /**
     * @dev Places a bid. The bid must be higher than the current highest bid
     * and the auction must be active.
     */
    function bid() external payable onlyDuringAuction {
        require(msg.value >= minBid, "Bid below minimum");
        require(msg.value > highestBid, "Bid not high enough");

        // Refund the previous highest bidder
        if (highestBidder != address(0)) {
            pendingReturns[highestBidder] += highestBid;
        }

        highestBidder = msg.sender;
        highestBid = msg.value;

        emit NewBid(msg.sender, msg.value);
    }

    /* -------------------------------------------------------------------------- */
    /*                                 Withdrawal Logic                            */
    /* -------------------------------------------------------------------------- */

    /**
     * @dev Withdraws any pending returns for the caller.
     */
    function withdraw() external returns (bool) {
        uint256 amount = pendingReturns[msg.sender];
        require(amount > 0, "Nothing to withdraw");

        // Set to zero before transfer to prevent re‑entrancy
        pendingReturns[msg.sender] = 0;

        (bool success, ) = msg.sender.call{value: amount}("");
        require(success, "Transfer failed");

        emit Withdrawal(msg.sender, amount);
        return true;
    }

    /* -------------------------------------------------------------------------- */
    /*                                 Auction Finalization                        */
    /* -------------------------------------------------------------------------- */

    /**
     * @dev Ends the auction. Can only be called by the owner after the auction
     * period has elapsed.
     */
    function endAuction() external onlyOwner onlyAfterAuction {
        require(!ended, "Already ended");
        ended = true;

        emit AuctionEnded(highestBidder, highestBid);
    }

    /**
     * @dev Allows the owner to withdraw the winning bid after the auction has ended.
     */
    function withdrawWinner() external onlyOwner onlyAfterAuction {
        require(ended, "Auction not ended");
        require(highestBidder != address(0), "No winner");

        uint256 amount = highestBid;
        highestBid = 0; // Prevent re‑entrancy and double withdrawal

        (bool success, ) = owner.call{value: amount}("");
        require(success, "Transfer failed");
    }

    /* -------------------------------------------------------------------------- */
    /*                                 Fallback Functions                          */
    /* -------------------------------------------------------------------------- */

    // Reject any direct ETH transfers to the contract
    receive() external payable {
        revert("Use bid() to place a bid");
    }
}

