pragma solidity ^0.8.0;


import "@openzeppelin/contracts/utils/Address.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract Auction {
    // Mapping of address to their bids
    mapping(address => uint256) public bids;

    // Mapping of address to whether they have been refunded or not
    mapping(address => bool) public refunded;

    // Highest bidder and bid amount
    address public highestBidder;
    uint256 public highestBid;

    // Auction start time, end time, and minimum bid
    uint256 public startTime;
    uint256 public endTime;
    uint256 public minBid;

    // Event emitted when a new bid is placed
    event NewBid(address bidder, uint256 amount);

    // Event emitted when the auction ends
    event AuctionEnded();

    // Event emitted when a withdrawal occurs
    event Withdrawn(address winner, uint256 amount);

    constructor(uint256 _startTime, uint256 _endTime, uint256 _minBid) {
        startTime = block.timestamp + _startTime;
        endTime = block.timestamp + _endTime;
        minBid = _minBid;
    }

    // Function to place a bid
    function bid(uint256 _amount) public {
        require(block.timestamp >= startTime && block.timestamp <= endTime, "Auction is not active");
        require(_amount > highestBid, "Bid must be higher than current highest bid");

        if (highestBidder != address(0)) {
            refunded[highestBidder] = true;
        }

        bids[msg.sender] = _amount;
        highestBidder = msg.sender;
        highestBid = _amount;

        emit NewBid(msg.sender, _amount);
    }

    // Function to end the auction
    function endAuction() public {
        require(block.timestamp > endTime, "Auction has not ended yet");

        if (highestBidder != address(0)) {
            refunded[highestBidder] = true;
        }

        emit AuctionEnded();
    }

    // Function to withdraw the winning bid
    function withdraw() public {
        require(highestBidder == msg.sender, "Only the highest bidder can withdraw");
