// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract SimpleVotingSystem {
    address public admin;
    bool public votingActive;
    mapping(uint256 => string) public candidates;
    mapping(address => uint256) public votes;
    mapping(address => bool) public hasVoted;
    mapping(uint256 => uint256) public candidateVotes;

    event CandidateRegistered(uint256 id, string name);
    event VoteCast(address voter, uint256 candidateId);
    event VotingEnded(string winner);

    constructor() {
        admin = msg.sender;
        votingActive = true;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not authorized");
        _;
    }

    function registerCandidate(uint256 id, string memory name) external onlyAdmin {
        require(keccak256(abi.encodePacked(candidates[id])) != keccak256(abi.encodePacked("")), "Candidate already registered");
        candidates[id] = name;
        emit CandidateRegistered(id, name);
    }

    function vote(uint256 candidateId) external {
        require(votingActive, "Voting has ended");
        require(!hasVoted[msg.sender], "Already voted");
        require(keccak256(abi.encodePacked(candidates[candidateId])) != keccak256(abi.encodePacked("")), "Candidate does not exist");

        candidateVotes[candidateId]++;
        votes[msg.sender] = candidateId;
        hasVoted[msg.sender] = true;
        emit VoteCast(msg.sender, candidateId);
    }

    function endVoting() external onlyAdmin {
        require(votingActive, "Voting already ended");
        votingActive = false;

        uint256 winningCandidateId = 0;
        uint256 maxVotes = 0;

        for (uint256 i = 1; i <= 100; i++) { // Assuming a maximum of 100 candidates
            if (candidateVotes[i] > maxVotes) {
                maxVotes = candidateVotes[i];
                winningCandidateId = i;
            }
        }

        emit VotingEnded(candidates[winningCandidateId]);
    }
}

