// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract VotingSystem {
    // Struct for candidate details
    struct Candidate {
        uint voteCount;
    }

    // Mapping of candidates to their IDs
    mapping(uint => Candidate) public candidates;

    // Mapping of voters to their votes
    mapping(address => bool) public voters;

    // Admin address
    address public admin;

    // Flag to check if voting is open
    bool public votingOpen;

    event CandidateRegistered(uint indexed candidateId);
    event VoteCast(address voter, uint indexed candidateId);
    event VotingEnded();

    constructor() {
        admin = msg.sender;
        votingOpen = true;
    }

    // Modifier to restrict function visibility to only the admin
    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin can perform this action");
        _;
    }

    // Function for candidate registration
    function registerCandidate(uint candidateId) public onlyAdmin {
        candidates[candidateId] = Candidate({voteCount: 0});
        emit CandidateRegistered(candidateId);
    }

    // Function to cast vote
    function vote(uint candidateId) public {
        require(votingOpen, "Voting period is closed");
        require(!voters[msg.sender], "Duplicate votes are not allowed");
        require(candidates[candidateId].voteCount > 0, "Candidate does not exist");

        voters[msg.sender] = true;
        candidates[candidateId].voteCount++;

        emit VoteCast(msg.sender, candidateId);
    }

    // Function to end voting period and tally votes
    function endVoting() public onlyAdmin {
        require(votingOpen, "Voting period is already closed");
        votingOpen = false;

        uint maxVotes = 0;
        uint winningCandidateId = 0;

        for (uint i=1; i<=candidates.length; i++) {
            if (candidates[i].voteCount > maxVotes) {
                maxVotes = candidates[i].voteCount;
                winningCandidateId = i;
            }
        }

        emit VotingEnded();
    }

    // Function to get the winner of the election
    function getWinner() public view returns (uint) {
        require(!votingOpen, "Voting period is still open");

        uint maxVotes = 0;
        uint winningCandidateId = 0;

        for (uint i=1; i<=candidates.length; i++) {
            if (candidates[i].voteCount > maxVotes) {
                maxVotes = candidates[i].voteCount;
                winningCandidateId = i;
            }
        }

        return winningCandidateId;
    }
}

