// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract MultiSigWallet {
    struct Transaction {
        address to;
        uint256 value;
        bytes data;
        bool executed;
    }

    mapping(address => bool) public owners;
    uint256 public requiredApprovals;
    uint256 public numOwners;
    Transaction[] public transactions;
    mapping(address => mapping(uint256 => bool)) public approvals;

    event Submitted(uint256 indexed txId);
    event Approved(uint256 indexed txId, address owner);
    event Executed(uint256 indexed txId);

    constructor(address[] memory _owners, uint256 _requiredApprovals) {
        require(_owners.length > 0 && _requiredApprovals > 0 && _requiredApprovals <= _owners.length, "Invalid parameters");

        for (uint256 i = 0; i < _owners.length; ++i) {
            owners[_owners[i]] = true;
        }

        requiredApprovals = _requiredApprovals;
        numOwners = _owners.length;
    }

    function submitTransaction(address _to, uint256 _value, bytes memory _data) public {
        require(owners[msg.sender], "Not an owner");

        transactions.push(Transaction(_to, _value, _data, false));

        emit Submitted(transactions.length - 1);
    }

    function approveTransaction(uint256 _txId) public {
        require(owners[msg.sender], "Not an owner");
        require(!approvals[msg.sender][_txId], "Already approved");

        Transaction storage tx = transactions[_txId];
        require(!tx.executed, "Transaction already executed");

        approvals[msg.sender][_txId] = true;

        emit Approved(_txId, msg.sender);
    }

    function executeTransaction(uint256 _txId) public {
        require(owners[msg.sender], "Not an owner");

        Transaction storage tx = transactions[_txId];
        require(!tx.executed, "Transaction already executed");

        uint256 numApprovals = 0;
        for (uint256 i = 0; i < numOwners; ++i) {
            if (approvals[address(this)[i]][_txId]) {
                ++numApprovals;
            }
        }

        require(numApprovals >= requiredApprovals, "Not enough approvals");

        tx.executed = true;

        (bool success, ) = tx.to.call{value: tx.value}(tx.data);
        if (!success) {
            revert();
        }

        emit Executed(_txId);
    }
}

