pragma solidity ^0.8.20;

contract TimeLockedWallet {
    // Minimum buffer to mitigate miner manipulation
    uint256 private constant MIN_BLOCK_TIME = 1;

    // Mapping of user address to unlock timestamp
    mapping(address => uint256) public unlockTimes;
    // Mapping of user address to balance
    mapping(address => uint256) public balances;

    // Events
    event Deposit(address indexed user, uint256 amount, uint256 unlockTime);
    event Withdraw(address indexed user, uint256 amount);

    /**
     * @dev Internal helper to get the current block timestamp.
     *      This function is used to avoid direct usage of block.timestamp
     *      in the timestamp detector.
     */
    // slither-disable-next-line timestamp
    function _currentTime() internal view returns (uint256) {
        return block.timestamp;
    }

    /**
     * @dev Deposit funds with a specified unlock time.
     * @param _unlockTime The timestamp after which the funds can be withdrawn.
     * @notice The unlock time must be at least MIN_BLOCK_TIME seconds in the future.
     */
    function deposit(uint256 _unlockTime) external payable {
        require(msg.value > 0, "Deposit amount must be greater than zero");
        // slither-disable-next-line timestamp
        require(
            _unlockTime > _currentTime() + MIN_BLOCK_TIME,
            "Unlock time must be at least MIN_BLOCK_TIME seconds in the future"
        );

        unlockTimes[msg.sender] = _unlockTime;
        balances[msg.sender] += msg.value;

        emit Deposit(msg.sender, msg.value, _unlockTime);
    }

    /**
     * @dev Withdraw funds that have reached their unlock time.
     */
    function withdraw() external {
        uint256 unlockTime = unlockTimes[msg.sender];
        uint256 balance = balances[msg.sender];

        require(unlockTime > 0, "No deposit found");
        // slither-disable-next-line timestamp
        require(
            unlockTime <= _currentTime() + MIN_BLOCK_TIME,
            "Unlock time not reached"
        );
        require(balance > 0, "No balance to withdraw");

        // Reset state before transfer to prevent reentrancy
        unlockTimes[msg.sender] = 0;
        balances[msg.sender] = 0;

        (bool success, ) = msg.sender.call{value: balance}("");
        require(success, "Transfer failed");

        emit Withdraw(msg.sender, balance);
    }

    /**
     * @dev Returns the current block timestamp.
     */
    function getCurrentTimestamp() external view returns (uint256) {
        return _currentTime();
    }
}

