pragma solidity ^0.8.20;

/// @title Subscription Service
/// @notice A simple subscription system that allows users to subscribe for a fixed duration.
/// @dev The contract stores subscription expirations and allows the owner to withdraw collected fees.
contract SubscriptionService {
    uint256 public constant SUBSCRIPTION_FEE = 0.01 ether;
    uint256 public constant SUBSCRIPTION_DURATION = 30 days;

    address public immutable owner;
    mapping(address => uint256) public expiration;
    uint256 public totalSubscribers;
    uint256 public totalRevenue;

    event NewSubscription(address indexed subscriber, uint256 expiration);
    event Renewal(address indexed subscriber, uint256 newExpiration);
    event Withdrawal(address indexed to, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    /// @notice Subscribe or renew a subscription.
    /// @dev The function is payable and requires the exact subscription fee.
    function subscribe() external payable {
        require(msg.value == SUBSCRIPTION_FEE, "Incorrect payment");
        totalRevenue += msg.value;

        uint256 currentTime = block.timestamp;
        // slither-disable-next-line timestamp
        if (expiration[msg.sender] <= currentTime) {
            expiration[msg.sender] = currentTime + SUBSCRIPTION_DURATION;
            totalSubscribers += 1;
            emit NewSubscription(msg.sender, expiration[msg.sender]);
        } else {
            expiration[msg.sender] += SUBSCRIPTION_DURATION;
            emit Renewal(msg.sender, expiration[msg.sender]);
        }
    }

    /// @notice Check if a user has an active subscription.
    /// @param user The address to check.
    /// @return True if the subscription is active, false otherwise.
    function isActive(address user) public view returns (bool) {
        // slither-disable-next-line timestamp
        return expiration[user] > block.timestamp;
    }

    /// @notice Withdraw collected fees to the owner.
    /// @dev Only the contract owner can call this function.
    function withdraw() external onlyOwner {
        uint256 balance = address(this).balance;
        require(balance > 0, "No funds");
        (bool success, ) = owner.call{value: balance}("");
        require(success, "Transfer failed");
        emit Withdrawal(owner, balance);
    }

    /// @notice Get the expiration timestamp for a user.
    /// @param user The address to query.
    /// @return The expiration timestamp.
    function getExpiration(address user) external view returns (uint256) {
        return expiration[user];
    }

    /// @notice Get the total number of subscribers.
    /// @return The total subscriber count.
    function getTotalSubscribers() external view returns (uint256) {
        return totalSubscribers;
    }

    /// @notice Get the total revenue collected.
    /// @return The total revenue in wei.
    function getTotalRevenue() external view returns (uint256) {
        return totalRevenue;
    }
}

