contract SubscriptionService {
    /* ------------------------------------------------------------------
     *  Constants
     * ------------------------------------------------------------------ */
    uint256 public constant SUBSCRIPTION_FEE = 0.1 ether;
    uint256 public constant SUBSCRIPTION_DURATION = 30 days;          // 2,592,000 seconds
    uint256 public constant BLOCK_TIME = 15;                          // Approximate block time in seconds
    uint256 public constant SUBSCRIPTION_DURATION_BLOCKS =
        SUBSCRIPTION_DURATION / BLOCK_TIME;                          // 172,800 blocks

    /* ------------------------------------------------------------------
     *  State Variables
     * ------------------------------------------------------------------ */
    // Expiration stored as block number when the subscription ends
    mapping(address => uint256) public expirationBlock;
    // Track whether an address has ever subscribed
    mapping(address => bool) public hasSubscribed;

    uint256 public totalSubscribers;
    uint256 public totalRevenue;

    address public immutable owner;

    /* ------------------------------------------------------------------
     *  Events
     * ------------------------------------------------------------------ */
    event NewSubscription(address indexed subscriber, uint256 expiration);
    event Renewal(address indexed subscriber, uint256 newExpiration);

    /* ------------------------------------------------------------------
     *  Modifiers
     * ------------------------------------------------------------------ */
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    modifier onlyActive() {
        require(isActive(msg.sender), "Subscription inactive");
        _;
    }

    /* ------------------------------------------------------------------
     *  Constructor
     * ------------------------------------------------------------------ */
    constructor() {
        owner = msg.sender;
    }

    /* ------------------------------------------------------------------
     *  Subscription Logic
     * ------------------------------------------------------------------ */
    /**
     * @dev Subscribe or renew a subscription.
     * The subscription is considered active if the current block number
     * is less than the stored expiration block number.
     */
    function subscribe() external payable {
        require(msg.value == SUBSCRIPTION_FEE, "Incorrect payment amount");

        uint256 currentExpBlock = expirationBlock[msg.sender];
        bool isRenewal = currentExpBlock > block.number;

        if (isRenewal) {
            expirationBlock[msg.sender] = currentExpBlock + SUBSCRIPTION_DURATION_BLOCKS;
            emit Renewal(
                msg.sender,
                block.timestamp + (expirationBlock[msg.sender] - block.number) * BLOCK_TIME
            );
        } else {
            expirationBlock[msg.sender] = block.number + SUBSCRIPTION_DURATION_BLOCKS;
            emit NewSubscription(
                msg.sender,
                block.timestamp + (expirationBlock[msg.sender] - block.number) * BLOCK_TIME
            );

            if (!hasSubscribed[msg.sender]) {
                hasSubscribed[msg.sender] = true;
                totalSubscribers++;
            }
        }

        totalRevenue += msg.value;
    }

    /**
     * @dev Check if a user has an active subscription.
     */
    function isActive(address user) public view returns (bool) {
        return expirationBlock[user] > block.number;
    }

    /* ------------------------------------------------------------------
     *  Owner Functions
     * ------------------------------------------------------------------ */
    /**
     * @dev Withdraw funds from the contract.
     */
    function withdraw(uint256 amount) external onlyOwner {
        require(amount <= address(this).balance, "Insufficient balance");
        payable(owner).transfer(amount);
    }
}

