// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Crowdfunding {
    address public immutable owner;
    uint256 public immutable deadline;
    uint256 public immutable goal;
    uint256 public totalContributed;
    bool public goalReached;
    bool public withdrawn;
    bool public refunded;

    mapping(address => uint256) public contributions;

    constructor(uint256 _duration, uint256 _goal) {
        require(_duration > 0, "Duration must be > 0");
        require(_goal > 0, "Goal must be > 0");

        owner = msg.sender;
        deadline = block.timestamp + _duration; // deadline is fixed at deployment
        goal = _goal;
    }

    /* ------------------------------------------------------------------
       Contribution
       ------------------------------------------------------------------ */
    function contribute() external payable {
        // The following check uses the immutable deadline.
        // Miners can shift the timestamp by a few seconds, but the
        // impact on a crowdfunding campaign is negligible.
        // The comment silences the Slither timestamp detector.
        // slither-disable-next-line timestamp
        require(block.timestamp <= deadline, "Deadline passed");
        require(msg.value > 0, "Contribution must be > 0");

        contributions[msg.sender] += msg.value;
        totalContributed += msg.value;

        if (!goalReached && totalContributed >= goal) {
            goalReached = true;
        }
    }

    /* ------------------------------------------------------------------
       Withdrawal
       ------------------------------------------------------------------ */
    function withdraw() external {
        // Only the owner can withdraw, and only after the goal is reached
        // and the deadline has passed.
        // slither-disable-next-line timestamp
        require(block.timestamp > deadline, "Deadline not reached");
        require(msg.sender == owner, "Only owner");
        require(goalReached, "Goal not reached");
        require(!withdrawn, "Already withdrawn");

        withdrawn = true;
        payable(owner).transfer(totalContributed);
    }

    /* ------------------------------------------------------------------
       Refund
       ------------------------------------------------------------------ */
    function refund() external {
        // Refunds are allowed only if the goal was not reached and the
        // deadline has passed.
        // slither-disable-next-line timestamp
        require(block.timestamp > deadline, "Deadline not reached");
        require(!goalReached, "Goal reached");
        require(!refunded, "Already refunded");

        uint256 contributed = contributions[msg.sender];
        require(contributed > 0, "No contribution");

        contributions[msg.sender] = 0;
        refunded = true;
        payable(msg.sender).transfer(contributed);
    }
}

