contract SubscriptionSystem {
    uint256 public constant SUBSCRIPTION_FEE = 0.1 ether;
    uint256 public constant SUBSCRIPTION_DURATION = 30 days;

    uint256 public totalSubscribers;
    uint256 public totalRevenue;

    mapping(address => uint256) public subscriptionExpiration;

    event SubscriptionCreated(address indexed user, uint256 expirationTimestamp);
    event SubscriptionRenewed(address indexed user, uint256 expirationTimestamp);

