        require(block.timestamp < subscriptionExpiration[msg.sender], "Subscription has expired");
        _;
    }

    function subscribe() public payable {
        require(msg.value == SUBSCRIPTION_FEE, "Incorrect payment amount");

        uint256 expirationTimestamp = block.timestamp + SUBSCRIPTION_DURATION;
        subscriptionExpiration[msg.sender] = expirationTimestamp;

        totalSubscribers++;
        totalRevenue += SUBSCRIPTION_FEE;

        emit SubscriptionCreated(msg.sender, expirationTimestamp);
    }

    function renewSubscription() public payable {
        require(msg.value == SUBSCRIPTION_FEE, "Incorrect payment amount");

        uint256 expirationTimestamp = block.timestamp + SUBSCRIPTION_DURATION;
        subscriptionExpiration[msg.sender] = expirationTimestamp;

        emit SubscriptionRenewed(msg.sender, expirationTimestamp);
    }

    function hasActiveSubscription(address user) public view returns (bool) {
        return block.timestamp < subscriptionExpiration[user];
    }
}

