contract TimeLockedWallet {
    address public immutable beneficiary;
    uint256 public unlockTime;
    uint256 private blockNumberAtSetUnlockTime;
    uint256 constant averageBlockTime = 15; // Assuming an average block time of 15 seconds

    event Deposit(address indexed sender, uint256 amount);
    event Withdrawal(address indexed to, uint256 amount);

    constructor(address _beneficiary) {
        require(_beneficiary != address(0), "Beneficiary cannot be the zero address");
        beneficiary = _beneficiary;
    }

    function setUnlockTime(uint256 _unlockTime) external {
        require(block.number < blockNumberAtSetUnlockTime + (_unlockTime / averageBlockTime), "Unlock time must be in the future");
        unlockTime = _unlockTime;
        blockNumberAtSetUnlockTime = block.number; // Store the current block number
    }

    receive() external payable {
        emit Deposit(msg.sender, msg.value);
    }

    function withdraw() external {
        require(msg.sender == beneficiary, "Only beneficiary can withdraw");
        uint256 elapsedBlocks = block.number - blockNumberAtSetUnlockTime;
        require(elapsedBlocks * averageBlockTime >= unlockTime, "Withdrawal not yet allowed");

        uint256 amount = address(this).balance;
        (bool success, ) = beneficiary.call{value: amount}("");
        require(success, "Transfer failed");

        emit Withdrawal(beneficiary, amount);
    }

    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }
}

