    address public buyer;
    address public seller;
    address public arbiter;
    uint256 public amount;
    State public state;

    event ContractInitialized(address indexed buyer, address indexed seller, address indexed arbiter, uint256 amount);
    event ItemDelivered();
    event PaymentReleased();
    event DisputeResolved(address winner, uint256 amount);
    event Refunded();

    constructor(address _seller, address _arbiter) payable {
        require(_seller != address(0), "Seller address cannot be zero");
        require(_arbiter != address(0), "Arbiter address cannot be zero");
        require(msg.value > 0, "Amount must be greater than zero");

        buyer = msg.sender;
        seller = _seller;
        arbiter = _arbiter;
        amount = msg.value;
        state = State.Created;

        emit ContractInitialized(buyer, seller, arbiter, amount);
    }

    modifier onlySeller() {
        require(msg.sender == seller, "Only seller can call this function");
        _;
    }

    modifier onlyBuyer() {
        require(msg.sender == buyer, "Only buyer can call this function");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == arbiter, "Only arbiter can call this function");
        _;
    }

    modifier notReleased() {
        require(state != State.Released && state != State.Refunded, "Payment already released or refunded");
        _;
    }

    modifier inDeliveredState() {
        require(state == State.Delivered, "Item must be marked as delivered");
        _;
    }

    function markAsDelivered() external onlySeller notReleased {
        state = State.Delivered;
        emit ItemDelivered();
    }

    function releasePayment() external onlyBuyer inDeliveredState notReleased {
        payable(seller).transfer(amount);
        state = State.Released;
        emit PaymentReleased();
    }

    function dispute() external onlyBuyer inDeliveredState notReleased {
        state = State.Disputed;
    }

    function resolveDispute(address winner) external onlyArbiter {
        require(state == State.Disputed, "Contract is not in disputed state");
        payable(winner).transfer(amount);
        if (winner == buyer) {
            state = State.Refunded;
            emit DisputeResolved(buyer, amount);
        } else if (winner == seller) {
            state = State.Released;
            emit DisputeResolved(seller, amount);
        }
    }

    receive() external payable {}
}

