contract Crowdfunding {
    address public creator;
    uint256 public goal;
    uint256 public deadlineBlockNumber;
    bool public isGoalReached;
    mapping(address => uint256) public contributions;
    mapping(address => bool) public claimedRefunds;
    event Contribution(address indexed contributor, uint256 amount);
    event Withdrawal(uint256 amount);
    event Refund(address indexed contributor, uint256 amount);

    constructor(uint256 _goal, uint256 _deadlineBlockNumber) {
        require(_deadlineBlockNumber > block.number + 10, "Deadline must be in the future");
        creator = msg.sender;
        goal = _goal;
        deadlineBlockNumber = _deadlineBlockNumber;
    }

    receive() external payable {}

    function contribute() external payable {
        require(block.number < deadlineBlockNumber, "Campaign has ended");
        contributions[msg.sender] += msg.value;
        emit Contribution(msg.sender, msg.value);
    }

    function checkGoalReached() internal view returns (bool) {
        return address(this).balance >= goal;
    }

    function withdrawFunds() external {
        require(msg.sender == creator, "Only the creator can withdraw funds");
        require(block.number > deadlineBlockNumber, "Deadline has not passed");
        isGoalReached = checkGoalReached();
        require(isGoalReached, "Goal not reached");

        uint256 amount = address(this).balance;
        payable(creator).transfer(amount);
        emit Withdrawal(amount);
    }

    function claimRefund() external {
        require(block.number > deadlineBlockNumber, "Deadline has not passed");
        isGoalReached = checkGoalReached();
        require(!isGoalReached, "Goal reached");

        uint256 amount = contributions[msg.sender];
        require(amount > 0, "No contribution to refund");
        require(!claimedRefunds[msg.sender], "Refund already claimed");

        payable(msg.sender).transfer(amount);
        claimedRefunds[msg.sender] = true;
        emit Refund(msg.sender, amount);
    }

    function getContribution(address _contributor) external view returns (uint256) {
        return contributions[_contributor];
    }
}

