contract VotingSystem {
    // Structure for storing candidate details
    struct Candidate {
        uint voteCount;
    }

    mapping(uint => Candidate) private candidates;
    mapping(address => bool) private voters;

    uint public totalCandidates = 0;
    address public admin;
    bool public votingOpen = false;

    event VotedEvent(string message);
    event RegisteredNewCandidate(uint candidateId, string name);
    event VotingEnded(bool didVoteRun);

    constructor() {
        // Set the deployer as admin
        admin = msg.sender;
    }

    function registerNewCandidate(string memory _name) public {
        require(msg.sender == admin, "Only admin can add new candidates");
        uint id = totalCandidates;
        candidates[id] = Candidate({voteCount: 0});
        emit RegisteredNewCandidate(id, _name);
        totalCandidates++;
    }

    function voteForCandidate(uint _candidateId) public {
        require(voters[msg.sender] == false, "One vote per address");
        require(_candidateId >= 0 && _candidateId < totalCandidates, "Invalid candidate id");
        require(votingOpen, "Voting period is closed");

        voters[msg.sender] = true;
        candidates[_candidateId].voteCount += 1;

        emit VotedEvent("You have voted for the candidate with ID: ");
    }

    function endVoting() public {
        require(msg.sender == admin, "Only admin can end voting");
        votingOpen = false;

        uint maxVotes = 0;
        uint winningCandidateId = 0;

        for (uint i=0; i < totalCandidates; i++) {
            if(candidates[i].voteCount > maxVotes){
                maxVotes = candidates[i].voteCount;
                winningCandidateId = i;
            }
        }

        emit VotingEnded(winningCandidateId == totalCandidates - 1);
    }

    function getWinner() public view returns (uint) {
        require(!votingOpen, "Voting is still open");

        uint maxVotes = 0;
        uint winningCandidateId = 0;

        for (uint i=0; i < totalCandidates; i++) {
            if(candidates[i].voteCount > maxVotes){
                maxVotes = candidates[i].voteCount;
                winningCandidateId = i;
            }
        }

        return winningCandidateId;
    }
}

