pragma solidity ^0.8.1;

contract Auction {
    uint public startTime;
    uint public endTime;
    uint public minBid;

    address payable public highestBidder;
    uint public highestBid;

    bool public ended = false;

    mapping(address => uint) public bids;

    event NewBid(address indexed bidder, uint amount);
    event AuctionEnded(address winner, uint amount);
    event Withdrawal(address indexed recipient, uint amount);

    constructor(uint _startTime, uint _endTime, uint _minBid) {
        require(_startTime > block.timestamp, "Start time must be in the future");
        require(_endTime > _startTime, "End time must be after start time");

        startTime = _startTime;
        endTime = _endTime;
        minBid = _minBid;
    }

    function bid() public payable {
        require(block.timestamp < endTime, "Auction has ended");
        require(msg.value > highestBid && msg.value >= minBid, "Your bid must be higher than the current highest bid and minimum bid amount");

        if (highestBid > 0) {
            payable(highestBidder).transfer(highestBid);

            emit NewBid(highestBidder, highestBid);
        }

        bids[msg.sender] = msg.value;
        highestBidder = payable(msg.sender);
        highestBid = msg.value;
    }

    function withdraw() public {
        require(ended, "Auction is not yet ended");

        uint amount = bids[msg.sender];
        if (amount > 0) {
            bids[msg.sender] = 0;

            payable(msg.sender).transfer(amount);

            emit Withdrawal(msg.sender, amount);
        }
    }

    function endAuction() public {
        require(!ended, "Auction already ended");
        require(block.timestamp >= endTime, "Auction has not yet ended");

        ended = true;

        if (highestBid > 0) {
            payable(highestBidder).transfer(highestBid);

            emit AuctionEnded(highestBidder, highestBid);
        }
    }

    function withdrawCreatorFunds() public {
        require(ended, "Auction is not yet ended");

        uint amount = address(this).balance;

        payable(msg.sender).transfer(amount);

        emit Withdrawal(msg.sender, amount);
    }
}

