// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract Auction {
    uint public startTime;
    uint public endTime;
    uint public minBid;

    address payable public highestBidder;
    uint public highestBid;

    bool public ended;

    mapping(address => uint) public bids;

    event AuctionStarted(uint startTime, uint endTime, uint minBid);
    event NewBid(address bidder, uint amount);
    event AuctionEnded(address winner, uint amount);
    event Withdrawal(address recipient, uint amount);

    error NotInAuction();
    error BidTooLow();
    error AuctionNotOver();

    constructor(uint _startTime, uint _endTime, uint _minBid) {
        startTime = block.number + _startTime;
        endTime = block.number + _endTime;
        minBid = _minBid;

        if (endTime <= block.number || startTime >= block.number + _endTime) {
            revert();
        }
    }

    function bid() public payable returns(bool) {
        uint currentBlockNumber = block.number;
        if (currentBlockNumber < startTime || currentBlockNumber > endTime) {
            revert NotInAuction();
        }

        uint amount = msg.value;

        if (amount <= minBid || amount <= highestBid && bids[msg.sender] + amount >= highestBid) {
            revert BidTooLow();
        }

        if (highestBidder != address(0)) {
            payable(highestBidder).transfer(bids[highestBidder]);
        }

        highestBid = amount;
        highestBidder = payable(msg.sender);
        bids[msg.sender] += amount;

        emit NewBid(msg.sender, amount);

        return true;
    }

    function endAuction() public {
        uint currentBlockNumber = block.number;
        if (currentBlockNumber < endTime) {
            revert AuctionNotOver();
        }

        ended = true;
        payable(highestBidder).transfer(bids[highestBidder]);

        emit AuctionEnded(highestBidder, highestBid);
    }

    function withdraw() public {
        uint currentBlockNumber = block.number;
        if (currentBlockNumber < endTime) {
            revert AuctionNotOver();
        }

        uint amount = bids[msg.sender];
        delete bids[msg.sender];

        payable(msg.sender).transfer(amount);

        emit Withdrawal(msg.sender, amount);
    }
}

